    hexi::binary_stream<decltype(adaptor)> stream(adaptor);
    uint32_t item_count = 0;
    stream >> item_count;

    // Calculate required size for items
    size_t required_size = sizeof(uint32_t) + item_count * (data_type ? sizeof(float) : sizeof(uint32_t));

