struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // 1. Create a buffer_adaptor from the input span
    hexi::buffer_adaptor adaptor(buffer);

    // 2. Use the buffer_adaptor's read_ptr() to get the current read pointer
    const auto read_pointer = adaptor.read_ptr();

    // 3. Use the buffer_adaptor's size() to check available data
    const auto available_data = adaptor.size();

    // Ensure we have enough data for the header (8 bytes)
    if (available_data < sizeof(PacketHeader)) {
        // Handle error - return default initialized header or throw exception
        return PacketHeader{};
    }

    // 4. Create a binary_stream from the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // 5. Use the binary_stream's span() method to get a zero-copy view of the header data
    auto header_span = stream.span<const uint8_t>(sizeof(PacketHeader));

    // 6. Copy the data from the span into the PacketHeader structure
    PacketHeader header;
    std::memcpy(&header, header_span.data(), sizeof(header));

    return header;
}
```

