std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance for the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> write_adaptor(buffer);

    // Check free space using free() before writing
    if (write_adaptor.free() < input_data.size()) {
        // Handle insufficient space (in real scenario, you might resize or throw)
        throw std::runtime_error("Insufficient buffer space");
    }

    // Write the input data using write()
    write_adaptor.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor instance for the same buffer
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check readable size using size()
    if (read_adaptor.size() != input_data.size()) {
        throw std::runtime_error("Buffer size mismatch");
    }

    // Read the data back using read() into a new vector
    std::vector<uint8_t> output_data(input_data.size());
    read_adaptor.read(output_data.data(), output_data.size());

    return output_data;
}

